// Error handling middleware
app.use((err, req, res, next) => {
    const clientIp = req.headers['x-forwarded-for'] || req.ip;
    const username = req.headers['x-username'] || 'unknown';

    winstonLogger.error(`Unhandled error: ${err.message} - User: ${username} - IP: ${clientIp}`, {
        stack: err.stack,
        url: req.originalUrl,
        method: req.method,
        body: req.body,
        headers: req.headers
    });

    res.status(500).json({ success: false, message: 'Internal server error' });
});

// 404 handler
app.use((req, res) => {
    const clientIp = req.headers['x-forwarded-for'] || req.ip;
    winstonLogger.warn(`404 Not Found: ${req.method} ${req.originalUrl} from IP ${clientIp}`);
    res.status(404).json({ success: false, message: 'Route not found' });
});

app.listen(PORT, () => {
    winstonLogger.info(`Audit logging server started on port ${PORT}`);
    winstonLogger.info(`Log files directory: ${logsDir}`);
    console.log(`Server running on http://localhost:${PORT}`);
});

module.exports = app;